// --- AUDIO BEEP HELPERS ---
const playErrorBeep = () => {
  try {
    const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContext) return;
    const ctx = new AudioContext();
    const osc = ctx.createOscillator();
    const gainNode = ctx.createGain();
    
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(150, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(80, ctx.currentTime + 0.3);
    
    gainNode.gain.setValueAtTime(0.3, ctx.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.3);
    
    osc.connect(gainNode);
    gainNode.connect(ctx.destination);
    osc.start();
    osc.stop(ctx.currentTime + 0.3);
  } catch (err) {
    console.error("Audio beep failed", err);
  }
};

const playSuccessBeep = () => {
  try {
    const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContext) return;
    const ctx = new AudioContext();
    const osc = ctx.createOscillator();
    const gainNode = ctx.createGain();
    
    osc.type = 'sine';
    osc.frequency.setValueAtTime(800, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(1200, ctx.currentTime + 0.1);
    
    gainNode.gain.setValueAtTime(0.1, ctx.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.1);
    
    osc.connect(gainNode);
    gainNode.connect(ctx.destination);
    osc.start();
    osc.stop(ctx.currentTime + 0.1);
  } catch (err) {
    console.error("Audio beep failed", err);
  }
};

const playThaiSpeechAlert = (text: string, customSoundUrl?: string) => {
  try {
    if (customSoundUrl) {
      const audio = new Audio(customSoundUrl);
      audio.play().catch(e => {
        console.warn("Custom sound failed, falling back to TTS", e);
        fallbackTTS(text);
      });
      return;
    }
    fallbackTTS(text);
  } catch (err) {
    console.error("Speech error", err);
  }
};

const speakText = (text: string) => {
  if (typeof window === "undefined" || !('speechSynthesis' in window)) return;

  try {
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = "en-US";
    
    // Attempt to select high quality English voices (Siri, Google, Alexa, premium, etc.)
    if (window.speechSynthesis.getVoices) {
      const voices = window.speechSynthesis.getVoices();
      const englishVoice = voices.find(v => 
        v.lang.toLowerCase().replace('_', '-').startsWith("en") && 
        (v.name.includes("Google") || v.name.includes("Siri") || v.name.includes("Premium") || v.name.includes("Natural") || v.name.includes("Zira"))
      ) || voices.find(v => v.lang.toLowerCase().replace('_', '-').startsWith("en"));
      
      if (englishVoice) {
        utterance.voice = englishVoice;
      }
    }

    // Avoid garbage collection issues in Chrome
    (window as any)._latestUtterance = utterance;
    
    window.speechSynthesis.speak(utterance);
  } catch (e) {
    console.error("Native speechSynthesis failed", e);
  }
};

const playSpeechConfirmation = (text: string, lang: "th" | "en" = "en") => {
  speakText(text);
};

const fallbackTTS = (text: string) => {
  let englishText = text;
  if (text === "ไม่พบสินค้าค่ะ กรุณาลองใหม่") {
    englishText = "Product not found. Please try again.";
  }
  speakText(englishText);
};

const exportToCSV = (data: any[], filename: string) => {
  if (data.length === 0) return;
  const headers = Object.keys(data[0]);
  const csvRows = [
    headers.join(','), // Header row
    ...data.map(row => 
      headers.map(fieldName => JSON.stringify(row[fieldName] || '')).join(',')
    )
  ];
  const csvContent = csvRows.join('\n');
  const blob = new Blob(['\ufeff' + csvContent], { type: 'text/csv;charset=utf-8;' }); // \ufeff for Excel UTF-8 BOM
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', filename);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};
