  // Polling customer display state
  useEffect(() => {
    if (!isCustomerDisplayState) return;

    const poll = async () => {
      try {
        const res = await fetch(`/api/customer-display/state?terminalId=${terminalId}`);
        if (res.ok) {
          const data = await res.json();
          if (data) {
            setCustomerDisplayData(data);
          }
        }
      } catch (err) {
        console.error("Polling error:", err);
      }
    };

    poll();
    const interval = setInterval(poll, 1000);
    return () => clearInterval(interval);
  }, [isCustomerDisplayState]);

  // Sync client-configured customer display ad parameters to server on startup
  useEffect(() => {
    if (isCustomerDisplayState) return;
    try {
      const storedAdUrl = localStorage.getItem("pos_customer_display_ad_url") || "";
      const storedAdType = (localStorage.getItem("pos_customer_display_ad_type") || "folder") as any;
      const storedAdEnabled = (localStorage.getItem("pos_customer_display_ad_enabled") || "true") === "true";
      const storedShowAdDuringCart = (localStorage.getItem("pos_customer_display_show_ad_during_cart") || "true") === "true";

      fetch("/api/customer-display/update", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          terminalId,
          adUrl: storedAdUrl,
          adType: storedAdType,
          adEnabled: storedAdEnabled,
          showAdDuringCart: storedShowAdDuringCart
        })
      }).catch(err => console.error("Initial ad sync error:", err));
    } catch (e) {
      console.error(e);
    }
  }, [isCustomerDisplayState]);

  useEffect(() => {
    const storedAdUrl = localStorage.getItem("pos_customer_display_ad_url") || "";
    const storedAdType = (localStorage.getItem("pos_customer_display_ad_type") || "folder") as any;
    const storedAdEnabled = (localStorage.getItem("pos_customer_display_ad_enabled") || "true") === "true";
    const storedShowAdDuringCart = (localStorage.getItem("pos_customer_display_show_ad_during_cart") || "true") === "true";
    setTempAdUrl(storedAdUrl);
    setTempAdType(storedAdType === "youtube" ? "folder" : storedAdType);
    setTempAdEnabled(storedAdEnabled);
    setTempShowAdDuringCart(storedShowAdDuringCart);
  }, []);

  // Load files from folder if adType is folder
  useEffect(() => {
    if (!isCustomerDisplayState) return;
    if (customerDisplayData.adType !== "folder") {
      setFolderFiles([]);
      return;
    }

    const folderPath = customerDisplayData.adUrl;
    if (!folderPath) return;

    fetch(`/api/customer-display/folder-files?path=${encodeURIComponent(folderPath)}`)
      .then(async (res) => {
        if (res.ok) {
          const data = await res.json();
          if (data.success && data.files) {
            setFolderFiles(data.files);
            setCurrentFileIdx(0);
            setFolderError(null);
          } else {
            setFolderError(data.error || "ไม่พบไฟล์สื่อในโฟลเดอร์นี้");
            setFolderFiles([]);
          }
        } else {
          const errData = await res.json().catch(() => ({}));
          setFolderError(errData.error || "เกิดข้อผิดพลาดในการโหลดไฟล์จากโฟลเดอร์");
          setFolderFiles([]);
        }
      })
      .catch((err) => {
        console.error("Fetch folder files error:", err);
        setFolderError("เชื่อมต่อระบบดึงข้อมูลโฟลเดอร์ล้มเหลว");
        setFolderFiles([]);
      });
  }, [isCustomerDisplayState, customerDisplayData.adUrl, customerDisplayData.adType]);

  // Automatically cycle through files in folder mode
  useEffect(() => {
    if (!isCustomerDisplayState || customerDisplayData.adType !== "folder" || folderFiles.length <= 1) return;

    const currentFile = folderFiles[currentFileIdx];
    if (!currentFile) return;

    if (!currentFile.isVideo) {
      const timer = setTimeout(() => {
        setCurrentFileIdx((prev) => (prev + 1) % folderFiles.length);
      }, 8000); // 8 seconds per image
      return () => clearTimeout(timer);
    }
  }, [isCustomerDisplayState, customerDisplayData.adType, folderFiles, currentFileIdx]);

  const handleNextFolderFile = () => {
    if (folderFiles.length > 0) {
      setCurrentFileIdx((prev) => (prev + 1) % folderFiles.length);
    }
  };

