  const showToast = (text: string, type: 'error' | 'warning' | 'success' = 'warning') => {
    const id = Date.now().toString() + Math.random().toString();
    setToastMessages(prev => [...prev, { id, text, type }]);
    setTimeout(() => {
      setToastMessages(prev => prev.filter(t => t.id !== id));
    }, 4000);
  };

  // Prevent unexpected closing/reloads and log forced exits for auditing, plus prevent F5 / Ctrl+R refresh
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      if (isLoggedIn && currentUser) {
        // Prompt dialog warning
        const message = "คุณกำลังจะออกจากระบบกะทันหันโดยไม่กดออกจากระบบอย่างปลอดภัย ข้อมูลนี้จะถูกบันทึกเพื่อตรวจสอบความโปร่งใส ปฏิเสธการปิดหรือไม่?";
        e.preventDefault();
        e.returnValue = message;
        return message;
      }
    };

    const handleUnload = () => {
      if (isLoggedIn && currentUser) {
        // Send keeping-alive log even if the tab is completely closed
        const payload = JSON.stringify({
          actionType: "forced_browser_close",
          performedBy: currentUser.id,
          authorizedBy: currentUser.id,
          details: `⚠️ ตรวจพบการบังคับปิดเว็บเบราว์เซอร์กะทันหัน (หรือรีเฟรชหน้าเว็บ) โดยพนักงาน: ${currentUser.name} (${currentUser.role}) โดยไม่ได้คลิกออกจากระบบหรือปิดกะอย่างถูกต้อง`,
        });
        
        fetch("/api/audit-logs", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: payload,
          keepalive: true,
        });
      }
    };

    const handleBlockRefresh = (e: KeyboardEvent) => {
      if (isLoggedIn) {
        const isF5 = e.key === "F5" || e.keyCode === 116;
        const isCtrlR = (e.ctrlKey || e.metaKey) && (e.key === "r" || e.key === "R" || e.code === "KeyR");
        
        if (isF5 || isCtrlR) {
          e.preventDefault();
          showToast("⚠️ ระบบความปลอดภัยล็อกการรีเฟรชหน้าเว็บ (F5 / Ctrl+R)! หากต้องการสิ้นสุดการทำงาน กรุณากดปุ่มออกจากระบบ หรือปิดแท็บเบราว์เซอร์แล้วเข้าใหม่เท่านั้น เพื่อความโปร่งใสและป้องกันการลักลอบรีเซ็ตข้อมูลกะ", "error");
        }
      }
    };

    window.addEventListener("beforeunload", handleBeforeUnload);
    window.addEventListener("unload", handleUnload);
    window.addEventListener("keydown", handleBlockRefresh, true);

    return () => {
      window.removeEventListener("beforeunload", handleBeforeUnload);
      window.removeEventListener("unload", handleUnload);
      window.removeEventListener("keydown", handleBlockRefresh, true);
    };
  }, [isLoggedIn, currentUser]);

