    setEmployeeFormCanManageStock(false);
    setEmployeeFormCanManagePromotions(false);
    setEmployeeFormCanViewHistory(false);
    setEmployeeFormCanViewReports(false);
    setEmployeeFormCanVoidBill(false);
    setEmployeeFormCanManualDiscount(false);
