    // 2. Supplier Form
    setNewSupName("");
    setNewSupContact("");
    setNewSupPhone("");
    setNewSupAddress("");
    setEditingSup(null);

    // 3. Member & Debtor Form
    setNewMemberName("");
    setNewMemberPhone("");
    setNewMemberPoints(0);
    setNewMemberIsDebtor(false);
    setEditingMember(null);
    setEditingDebtorId(null);

    // 4. Product Form
    setEditingProduct(null);

    // 5. Category Form
    setEditingCat(null);
    setEditingCatName("");

    // 6. Promotions Form
    setPromoFormName("");
    setPromoFormDesc("");
    setPromoFormType("quantity_discount");
    setPromoFormApplyTo("product");
    setPromoFormProductUnitId("");
    setPromoFormCategoryId("");
    setPromoFormCustomProductUnitIds([]);
    setPromoFormMinQty("3");
    setPromoFormDiscount("1.00");
    setPromoFormDiscountPercent("");
    setPromoFormMinimumAmount("");
    setPromoFormFreeUnitId("");
    setPromoFormFreeQty("1");
    setPromoFormIsActive(true);

    // 7. Stock-In Form
    setStockInProductId("");
    setStockInProductUnitId("");
    setStockInSupplierId("");
    setStockInQuantity("");
    setStockInCostPrice("");
    setStockInDate(getTodayDateString());
