  const filteredShifts = shiftsList.filter((shift) => {
    if (currentUser?.role === "cashier" && shift.cashierId !== currentUser.id) {
      return false;
    }
    if (shiftFilterCashier !== "all" && String(shift.cashierId) !== shiftFilterCashier) {
      return false;
    }
    if (shiftFilterStatus !== "all" && shift.status !== shiftFilterStatus) {
      return false;
    }
    if (shiftFilterStartDate) {
      const shiftDateStr = getLocalDateString(shift.startTime);
      if (shiftDateStr < shiftFilterStartDate) return false;
    }
    if (shiftFilterEndDate) {
      const shiftDateStr = getLocalDateString(shift.startTime);
      if (shiftDateStr > shiftFilterEndDate) return false;
    }
    return true;
  });

  const handleExportShiftsToCSV = () => {
    try {
      const headers = [
        "รหัสกะ (Shift ID)",
        "สถานะ (Status)",
        "ชื่อพนักงาน (Cashier Name)",
        "เวลาเปิดกะ (Start Time)",
        "เวลาปิดกะ (End Time)",
        "เงินทอนเริ่มต้น (Start Cash)",
        "ยอดขายตามระบบ (Expected endCash)",
        "ยอดเงินนับจริง (Actual Cash)",
        "ส่วนต่าง (Difference)"
      ];

      const rows = filteredShifts.map((shift) => [
        `#${shift.id}`,
        shift.status === "open" ? "กำลังเปิดกะ" : "ปิดกะแล้ว",
        shift.cashierName || "ไม่ทราบชื่อ",
        new Date(shift.startTime).toLocaleString("th-TH"),
        shift.endTime ? new Date(shift.endTime).toLocaleString("th-TH") : "-",
        shift.startCash || "0.00",
        shift.status === "closed" ? (shift.endCash || "0.00") : "-",
        shift.status === "closed" ? (shift.actualCash || "0.00") : "-",
        shift.status === "closed" ? (shift.difference || "0.00") : "-"
      ]);

      const csvContent = "\uFEFF" + [
        headers.join(","),
        ...rows.map(row => row.map(val => `"${String(val).replace(/"/g, '""')}"`).join(","))
      ].join("\n");

      const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.setAttribute("href", url);
      link.setAttribute("download", `รายงานกะทำงาน_${getTodayDateString()}.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      showToast("ส่งออกไฟล์รายงานกะสำเร็จแล้ว (CSV)", "success");
    } catch (err: any) {
      showToast("ล้มเหลวในการส่งออกไฟล์: " + err.message, "error");
    }
  };

  // Dashboard operation action: Record Stock-In Entry Inbound Log
  const handleAddPoItem = (unitId: string) => {
    const unit = productsList.flatMap(p => p.units || []).find(u => u.id.toString() === unitId);
    if (!unit) return;
    const prod = productsList.find(p => p.id === unit.productId);
    if (!prod) return;

    setPoItems(prev => {
      const existing = prev.find(i => i.productUnitId === parseInt(unitId));
      if (existing) {
        return prev.map(i => 
          i.productUnitId === parseInt(unitId) 
            ? { ...i, quantity: i.quantity + 1, subtotal: (i.quantity + 1) * i.costPrice } 
            : i
        );
      }
      return [...prev, {
        productId: prod.id,
        productUnitId: unit.id,
        name: `${prod.name} (${unit.unitName})`,
        quantity: 1,
        costPrice: parseFloat(unit.costPrice) || 0,
        subtotal: parseFloat(unit.costPrice) || 0
      }];
    });
    setPoSearchTerm("");
  };

  const handleUpdatePoItemQty = (index: number, newQty: number) => {
    if (newQty < 1) return;
    const newItems = [...poItems];
    newItems[index].quantity = newQty;
    newItems[index].subtotal = newQty * newItems[index].costPrice;
    setPoItems(newItems);
  };
  
  const handleUpdatePoItemCost = (index: number, newCost: number) => {
    if (newCost < 0) return;
    const newItems = [...poItems];
    newItems[index].costPrice = newCost;
    newItems[index].subtotal = newItems[index].quantity * newCost;
    setPoItems(newItems);
  };

  const handleRemovePoItem = (index: number) => {
    setPoItems(prev => prev.filter((_, i) => i !== index));
  };

