          printWindow.document.write('<style>@import url("https://cdn.jsdelivr.net/npm/tailwindcss@2.2.19/dist/tailwind.min.css"); @media print { @page { size: A4; margin: 15mm; } body { font-family: "Sarabun", sans-serif; } }</style>');
