  const handleClearData = async (level: number) => {
    let confirmMsg = "";
    if (level === 1) confirmMsg = "คุณแน่ใจหรือไม่ว่าต้องการล้างข้อมูลการขายและรายการบิลทั้งหมด? (จะไม่ลบสินค้าหรือสมาชิก)";
    else if (level === 2) confirmMsg = "คำเตือน: คุณกำลังจะล้างข้อมูลทุกอย่างรวมถึง สินค้า, สมาชิก, โปรโมชั่น, บิลการขาย (ยกเว้นผู้ใช้งานและการตั้งค่าร้าน) ยืนยันใช่หรือไม่?";
    else if (level === 3) confirmMsg = "คำเตือนระดับสูงสุด ⚠️: คุณกำลังจะลบข้อมูลทั้งหมดในระบบกลับไปเป็นค่าเริ่มต้น (Factory Reset) ข้อมูลผู้ใช้และการตั้งค่าจะถูกลบด้วย คุณแน่ใจหรือไม่?";

    if (!window.confirm(confirmMsg)) return;

    try {
      showToast("กำลังล้างข้อมูล กรุณารอสักครู่...", "success");
      const res = await fetch("/api/clear-data", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ level })
      });
      const data = await res.json();
      if (res.ok) {
        showToast(data.message, "success");
        if (level === 3) {
          setIsLoggedIn(false);
          setCurrentUser(null);
        }
        setTimeout(() => window.location.reload(), 1500);
      } else {
        throw new Error(data.error);
      }
    } catch (err: any) {
      showToast("ล้มเหลว: " + err.message, "error");
    }
  };

  const handleBackupDatabase = async () => {
    try {
      showToast("กำลังสร้างไฟล์สำรองข้อมูล กรุณารอสักครู่...", "success");
      const res = await fetch("/api/backup");
      if (!res.ok) throw new Error("ไม่สามารถดาวน์โหลดข้อมูลสำรองได้");
      const blob = await res.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `backup_pos_${new Date().getTime()}.json`;
      a.click();
      window.URL.revokeObjectURL(url);
    } catch (err: any) {
      showToast("ล้มเหลว: " + err.message, "error");
    }
  };

  const handleRestoreDatabase = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    
    if (!window.confirm("⚠️ คำเตือน: การกู้คืนจะเขียนทับข้อมูลทั้งหมดในระบบปัจจุบัน คุณต้องการดำเนินการต่อหรือไม่?")) {
      e.target.value = '';
      return;
    }

    try {
      showToast("กำลังกู้คืนข้อมูล กรุณารอสักครู่...", "success");
      const text = await file.text();
      const parsedData = JSON.parse(text);
      
      const res = await fetch("/api/restore", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(parsedData)
      });
      
      const resData = await res.json();
      if (res.ok) {
        showToast("กู้คืนข้อมูลเรียบร้อย ระบบจะโหลดข้อมูลใหม่...", "success");
        setTimeout(() => window.location.reload(), 1500);
      } else {
        throw new Error(resData.error);
      }
    } catch (err: any) {
      showToast("ล้มเหลว: " + err.message, "error");
    } finally {
      e.target.value = '';
    }
  };

  const handleExportExcel = () => {
    showToast("กำลังสร้างไฟล์ Excel (XLSX)...", "success");
    const wsData = [
      ["ชื่อสินค้า", "หมวดหมู่", "สต็อกคงเหลือ", "เกณฑ์ขั้นต่ำ", "บาร์โค้ด", "ชื่อหน่วย", "ตัวคูณ (Conversion)", "ราคาขาย", "ราคาต้นทุน", "รายละเอียด"]
    ];
    
    productsList.forEach(p => {
      if (p.units && p.units.length > 0) {
        p.units.forEach((u: any) => {
          wsData.push([
            p.name,
            p.category,
            p.stockQuantity,
            p.minStock,
            u.barcode,
            u.unitName,
            u.conversionFactor,
            u.retailPrice,
            u.costPrice || "0.00",
            p.description || ""
          ]);
        });
      } else {
        wsData.push([
          p.name,
          p.category,
          p.stockQuantity,
          p.minStock,
          "ไม่มีบาร์โค้ด",
          "ชิ้น",
          1,
          0,
          0,
          p.description || ""
        ]);
      }
    });

    const ws = XLSX.utils.aoa_to_sheet(wsData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Products");
    XLSX.writeFile(wb, `products_export_${new Date().getTime()}.xlsx`);
  };

  const handleImportExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      showToast("กำลังอ่านไฟล์ Excel...", "success");
      const buffer = await file.arrayBuffer();
      const wb = XLSX.read(buffer, { type: "array" });
      const wsName = wb.SheetNames[0];
      const ws = wb.Sheets[wsName];
      const jsonData: any[] = XLSX.utils.sheet_to_json(ws, { header: 1 });
      
      jsonData.shift(); // Remove header row
      
      const productsMap = new Map();
      const generatedBarcodesInBatch = new Set<string>();
      
      jsonData.forEach((row: any) => {
        if (!row[0]) return;
        
        const prodName = String(row[0]).trim();
        const category = String(row[1] || "ทั่วไป").trim();
        const stockQuantity = parseInt(row[2]) || 0;
        const minStock = parseInt(row[3]) || 10;
        
        let barcode = String(row[4] || "").trim();
        if (!barcode) {
          // Generate a 12-digit random number and calculate EAN-13 Check Digit
          const generateEan13 = () => {
            let digits = "";
            for (let i = 0; i < 12; i++) {
              digits += Math.floor(Math.random() * 10).toString();
            }
            let sumOdd = 0;
            let sumEven = 0;
            for (let i = 0; i < 12; i++) {
              const val = parseInt(digits[i], 10);
              if (i % 2 === 0) {
                sumOdd += val;
              } else {
                sumEven += val;
              }
            }
            const total = sumOdd + (sumEven * 3);
            const checkDigit = (10 - (total % 10)) % 10;
            return digits + checkDigit;
          };
          
          let b = generateEan13();
          while (generatedBarcodesInBatch.has(b)) {
            b = generateEan13();
          }
          barcode = b;
          generatedBarcodesInBatch.add(b);
        }

        const unitName = String(row[5] || "ชิ้น").trim();
        const conversionFactor = parseInt(row[6]) || 1;
        const retailPrice = parseFloat(row[7]) || 0;
        const costPrice = parseFloat(row[8]) || 0;
        const description = String(row[9] || "").trim();
        
        const unit = { barcode, unitName, conversionFactor, retailPrice, costPrice, wholesalePrice: retailPrice };

        if (productsMap.has(prodName)) {
          productsMap.get(prodName).units.push(unit);
        } else {
          productsMap.set(prodName, {
            name: prodName, category, description, baseUnit: unitName, stockQuantity, minStock, units: [unit]
          });
        }
      });
      
      const productsArray = Array.from(productsMap.values());
      if (productsArray.length === 0) {
        showToast("ไม่พบข้อมูลสินค้าที่สามารถนำเข้าได้", "warning");
        return;
      }
      
      showToast(`กำลังนำเข้าสินค้า ${productsArray.length} รายการ กรุณารอสักครู่...`, "success");
      
      const res = await fetch("/api/products/bulk", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ products: productsArray })
      });
      
      let data: any;
      const responseText = await res.text();
      try {
        data = JSON.parse(responseText);
      } catch (parseErr) {
        throw new Error(`เซิร์ฟเวอร์ตอบกลับไม่เป็นไปตามรูปแบบ (Status: ${res.status}): ${responseText.substring(0, 100)}...`);
      }

      if (res.ok) {
        showToast(`นำเข้าสำเร็จ ${data.count} รายการ`, "success");
        await fetchInitialData();
      } else {
        throw new Error(data.error || "เซิร์ฟเวอร์รายงานข้อผิดพลาด");
      }
    } catch (err: any) {
      showToast("ล้มเหลว: " + err.message, "error");
    } finally {
      e.target.value = '';
    }
  };

