  // Handle Mock Login Submission
  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!loginUsername.trim() || !loginPassword.trim()) {
      setAuthError("กรุณากรอกชื่อล็อกอินและรหัสผ่าน");
      return;
    }
    
    // Check if user exists in our seeded database via username
    const user = availableUsers.find(u => u.username.toLowerCase() === loginUsername.toLowerCase().trim());
    
    if (user) {
      // Validate password
      if (user.password === loginPassword) {
        setCurrentUser(user);
        setIsLoggedIn(true);
        setAuthError("");
        setCart([]); 
        setTimeout(() => barcodeInputRef.current?.focus(), 100);
        logAuditEvent("user_login", user.id, user.id, `🔐 ผู้ใช้ ${user.name} (${user.role}) เข้าสู่ระบบสำเร็จ`);
        
        if (loginMode === 'mobile') {
          setDashboardSubTab("reports");
          setActiveTab("dashboard");
        } else if (user.canAccessPos) {
          setActiveTab("pos");
        } else if (user.role === "admin" || user.role === "owner" || user.role === "backoffice" || user.canViewReports || user.canManageBackend) {
          setActiveTab("dashboard");
        } else if (user.canManageStock) {
          setActiveTab("products");
        } else if (user.canViewHistory) {
          setActiveTab("audit");
        } else {
          setActiveTab("pos");
        }
      } else {
        setAuthError("รหัสผ่านไม่ถูกต้อง");
      }
    } else {
      setAuthError("ไม่พบบัญชีผู้ใช้นี้ในระบบ");
    }
  };

