  const handleCheckoutSubmit = async (methodOverridden?: string, receivedCashVal?: string) => {
    if (isSubmittingCheckoutRef.current) return;
    isSubmittingCheckoutRef.current = true;
    setIsSubmittingCheckout(true);

    if (cart.length === 0) {
      showToast("กรุณาเลือกสินค้าลงตะกร้าก่อนทำรายการค่ะ", "warning");
      isSubmittingCheckoutRef.current = false;
      setIsSubmittingCheckout(false);
      return;
    }

    const finalMethod = isSplitPaymentModalOpen ? "split" : (methodOverridden || paymentMethod);
    
    // If receivedCashVal is specified (like from quick cash buttons), we use it.
    // Otherwise, if receivedAmount is not empty, we use it.
    // Otherwise, if payment method is cash, we default to the exact total amount (exact change).
    let finalReceived = receivedCashVal;
    if (finalReceived === undefined) {
      if (receivedAmount !== "") {
        finalReceived = receivedAmount;
      } else {
        finalReceived = cartTotalAmount.toString();
      }
    }

    // Shift check
    if (isShiftSystemEnabled && !activeShift) {
      showToast("กรุณาเปิดกะแคชเชียร์ก่อนทำการขายสินค้าค่ะ", "error");
      isSubmittingCheckoutRef.current = false;
      setIsSubmittingCheckout(false);
      return;
    }

    // Split Payment Validation
    let splitCashVal = null;
    let splitTransferVal = null;
    let splitWelfareVal = null;

    if (finalMethod === "split") {
      const isInvalidInput = (val: string) => {
        if (!val) return false;
        const trimmed = val.trim();
        if (trimmed === "" || trimmed === ".") return true;
        return isNaN(parseFloat(trimmed));
      };

      if (isInvalidInput(splitCash) || isInvalidInput(splitTransfer) || isInvalidInput(splitWelfare)) {
        showToast("กรุณาระบุจำนวนเงินในการแยกจ่ายให้ถูกต้อง (ห้ามป้อนทศนิยมเดี่ยวหรือตัวอักษรที่ไม่ใช่ตัวเลข)ค่ะ", "warning");
        isSubmittingCheckoutRef.current = false;
        setIsSubmittingCheckout(false);
        return;
      }

      const cash = safeParseSplitVal(splitCash);
      const transfer = safeParseSplitVal(splitTransfer);
      const welfare = safeParseSplitVal(splitWelfare);
      
      const sum = cash + transfer + welfare;
      if (Math.abs(sum - cartTotalAmount) > 0.05) {
        showToast("ยอดเงินแยกจ่ายรวมกันต้องเท่ากับยอดสุทธิใบเสร็จค่ะ", "warning");
        isSubmittingCheckoutRef.current = false;
        setIsSubmittingCheckout(false);
        return;
      }
      splitCashVal = cash;
      splitTransferVal = transfer;
      splitWelfareVal = welfare;
    }

    // Cash verification
    if (finalMethod === "cash") {
      const rAmt = parseFloat(finalReceived || "0");
      if (rAmt < cartTotalAmount) {
        showToast("จำนวนเงินสดที่รับมาไม่เพียงพอกับยอดชำระค่ะ", "warning");
        isSubmittingCheckoutRef.current = false;
        setIsSubmittingCheckout(false);
        return;
      }
    }

    // Credit validation
    if (finalMethod === "credit") {
      if (!selectedMember) {
        showToast("กรุณาเลือกสมาชิก/ลูกหนี้ที่ต้องการชำระด้วยเงินเชื่อค่ะ", "warning");
        isSubmittingCheckoutRef.current = false;
        setIsSubmittingCheckout(false);
        return;
      }
      if (!selectedMember.isDebtor) {
        showToast(`สมาชิก "${selectedMember.name}" ยังไม่ได้รับสิทธิ์หรือเปิดบัญชีจ่ายเชื่อค่ะ`, "warning");
        isSubmittingCheckoutRef.current = false;
        setIsSubmittingCheckout(false);
        return;
      }
    }

    try {
      const itemsPayload = promotionResults.processedCart.map((item) => {
        const isFree = !!(item as any).isFreebie;
        const price = isFree ? 0 : (item.overridePrice !== undefined ? item.overridePrice : item.basePrice);
        return {
          type: item.type,
          id: item.id,
          qty: item.qty,
          overridePrice: price,
          overrideApprovedBy: item.overrideApprovedBy || null,
        };
      });

      const payload = {
        cashierId: currentUser?.id,
        saleType: saleType,
        discount: (manualDiscount + promotionResults.totalPromoDiscount + pointsDiscountValue).toString(),
        receivedAmount: finalReceived || "0",
        paymentMethod: finalMethod,
        splitCashAmount: splitCashVal !== null ? splitCashVal.toString() : null,
        splitTransferAmount: splitTransferVal !== null ? splitTransferVal.toString() : null,
        splitWelfareAmount: splitWelfareVal !== null ? splitWelfareVal.toString() : null,
        items: itemsPayload,
        memberId: selectedMember?.id || null,
        pointsRedeemed: pointsRedeemed,
        debtorId: selectedMember?.isDebtor ? selectedMember.id : null,
        shiftId: activeShift?.id || null,
        clientCreatedAt: new Date().toISOString(),
      };

      const res = await fetch("/api/orders", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || "ทำรายการชำระเงินไม่สำเร็จ");
      }

      const completedOrder = await res.json();
      showToast("✓ ออกใบเสร็จและชำระเงินสำเร็จแล้ว!", "success");

      // Reset cart and modals
      setCart([]);
      setSelectedMember(null);
      setPointsRedeemed(0);
      setManualDiscount(0);
      setReceivedAmount("");
      setSplitCash("");
      setSplitTransfer("");
      setSplitWelfare("");
      setIsPaymentModalOpen(false);
      setIsSplitPaymentModalOpen(false);
      
      // Set receipt for display or printing
      setCompletedOrderReceipt(completedOrder);
      setLastPrintedOrderReceipt(completedOrder);
      setShouldTriggerPrint(isAutoPrintEnabled);

      // Speak detailed confirmation with received cash and change amount in English if enabled
      if (storeCheckoutVoiceEnabled) {
        const totalAmt = parseFloat(completedOrder.totalAmount || cartTotalAmount.toString());
        const rAmt = parseFloat(completedOrder.receivedAmount || "0");
        const changeAmt = parseFloat(completedOrder.changeAmount || "0");
        const method = completedOrder.paymentMethod || finalMethod;

        let textToSpeak = "";
        if (method === "cash") {
          if (changeAmt > 0) {
            textToSpeak = `Payment successful. Total amount is ${totalAmt} Baht. Received ${rAmt} Baht. Change is ${changeAmt} Baht.`;
          } else {
            textToSpeak = `Payment successful. Total amount is ${totalAmt} Baht. Exact change received.`;
          }
        } else {
          textToSpeak = `Payment successful. Total amount is ${totalAmt} Baht.`;
        }
        playSpeechConfirmation(textToSpeak, "en");
      }

      // Refresh data
      fetchInitialData();
      
      setTimeout(() => {
        barcodeInputRef.current?.focus();
      }, 100);

    } catch (err: any) {
      showToast(err.message, "error");
    } finally {
      isSubmittingCheckoutRef.current = false;
      setIsSubmittingCheckout(false);
    }
  };

