  const generateAutoBarcode = (): string => {
    let finalBarcode = "";
    let attempts = 0;
    while (attempts < 100) {
      const prefix = "290";
      const randomPart = Math.floor(100000000 + Math.random() * 900000000).toString();
      const temp = prefix + randomPart;
      let sum = 0;
      for (let idx = 0; idx < 12; idx++) {
        sum += parseInt(temp[idx]) * (idx % 2 === 0 ? 1 : 3);
      }
      const checkDigit = (10 - (sum % 10)) % 10;
      const barcodeCandidate = temp + checkDigit;

      let isDuplicate = false;
      for (const p of productsList) {
        if (p.units && Array.isArray(p.units)) {
          if (p.units.some((u: any) => u.barcode === barcodeCandidate)) {
            isDuplicate = true;
            break;
          }
        }
      }
      if (!isDuplicate) {
        finalBarcode = barcodeCandidate;
        break;
      }
      attempts++;
    }
    if (!finalBarcode) {
      finalBarcode = "290" + Date.now().toString().slice(-10);
    }
    return finalBarcode;
  };

