                            <label className="font-bold text-slate-600">รูปแบบโปรโมชั่น *</label>
                            <select
                              className="bg-slate-50 border border-slate-200 rounded-xl py-2 px-3 text-slate-800 focus:outline-none focus:ring-1 focus:ring-slate-400 font-bold"
